import{_ as e,c as a,a1 as n,o}from"./chunks/framework.BDxlaA_J.js";const f=JSON.parse('{"title":"What is Footprinting and Reconnaissance?","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md"}'),i={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md"};function r(s,t,c,p,h,g){return o(),a("div",null,t[0]||(t[0]=[n('<h1 id="what-is-footprinting-and-reconnaissance" tabindex="-1">What is Footprinting and Reconnaissance? <a class="header-anchor" href="#what-is-footprinting-and-reconnaissance" aria-label="Permalink to &quot;What is Footprinting and Reconnaissance?&quot;">​</a></h1><p>Footprinting (also known as reconnaissance) is the technique used for gathering information about computer systems and the entities they belong to. To get this information, a hacker might use various tools and technologies. This information is very useful to a hacker who is trying to crack a whole system.</p><p>When used in the computer security lexicon, &quot;Footprinting&quot; generally refers to one of the pre-attack phases; tasks performed before doing the actual attack. Some of the tools used for Footprinting are Sam Spade, nslookup, traceroute, Nmap and neotrace.</p><p>Footprinting helps to:</p><p><strong>Know Security Posture</strong> – The data gathered will help us to get an overview of the security posture of the company such as details about the presence of a firewall, security configurations of applications etc.</p><p><strong>Reduce Attack Area</strong> – Can identify a specific range of systems and concentrate on particular targets only. This will greatly reduce the number of systems we are focussing on.</p><p><strong>Identify vulnerabilities</strong> – we can build an information database containing the vulnerabilities, threats, loopholes available in the system of the target organization.</p><p><strong>Draw Network map</strong> – helps to draw a network map of the networks in the target organization covering topology, trusted routers, presence of server and other information.</p><p>Source: <a href="https://en.wikipedia.org/wiki/Footprinting" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Footprinting</a><a href="https://www.greycampus.com/opencampus/ethical-hacking/what-is-footprinting" target="_blank" rel="noreferrer">https://www.greycampus.com/opencampus/ethical-hacking/what-is-footprinting</a></p>',9)]))}const u=e(i,[["render",r]]);export{f as __pageData,u as default};
